;=======================================================================================
; UI/FCM tile and glyph data.
;
; Compiles standalone into the `uitiles` asset (loaded from disk at boot). The
; payload is laid out at the offsets in shared/ui_tile_layout.asm; tileloader.asm
; DMAs from those same offsets. The ui_glyph_* bitmaps MUST stay in
; UI_TEXT_A..UI_TEXT_COLON order, since the index/offsets are generated by loops.
;
; Record format:
;   .word tile id
;   .word payload size
;   .byte payload bytes
;=======================================================================================

        .cpu "45gs02"
        .include "../platform.asm"
        .include "../shared/ui_tile_layout.asm"

; Origin is irrelevant: position-independent data. It only sets the 2-byte PRG
; load-address header, which the boot loader strips (DMAs body from staging+2).
; $0000 so no reader infers a real address.
        * = $0000

ui_tiles_start:

; Text glyph border colour. Set to $0C (light grey, same as UI_TILE_PANEL
; and UI_TILE_MENU) so glyphs blend into the panel + chrome bar instead of
; punching cyan rectangles around each letter on the popup. Foreground is
; black -- baked in at asset-build time.
UI_TEXT_BG = $0C
UI_TEXT_FG = $00

UI_TEXT_ROW .macro p0, p1, p2, p3, p4
        .byte UI_TEXT_BG, \p0, \p1, \p2, \p3, \p4, UI_TEXT_BG, UI_TEXT_BG
.endmacro

; Commodore-style glyph macros. CBM_ROW takes one byte (8 bits, MSB first) and
; expands it into 8 palette indices (UI_TEXT_FG where the bit is 1, UI_TEXT_BG
; where 0). CBM_GLYPH stacks 8 rows of CBM_ROW into a full 8x8 FCM cell.
;
; The byte data matches the standard C64 character ROM bitmaps for uppercase
; A-Z, 0-9 and a handful of punctuation. Copy/paste from any C64 charset table
; (e.g. CHARGEN at $D000 in the C64 memory map).
CBM_ROW .macro b
        .byte (\b) & $80 ? UI_TEXT_FG : UI_TEXT_BG
        .byte (\b) & $40 ? UI_TEXT_FG : UI_TEXT_BG
        .byte (\b) & $20 ? UI_TEXT_FG : UI_TEXT_BG
        .byte (\b) & $10 ? UI_TEXT_FG : UI_TEXT_BG
        .byte (\b) & $08 ? UI_TEXT_FG : UI_TEXT_BG
        .byte (\b) & $04 ? UI_TEXT_FG : UI_TEXT_BG
        .byte (\b) & $02 ? UI_TEXT_FG : UI_TEXT_BG
        .byte (\b) & $01 ? UI_TEXT_FG : UI_TEXT_BG
.endmacro

CBM_GLYPH .macro b0, b1, b2, b3, b4, b5, b6, b7
        #CBM_ROW \b0
        #CBM_ROW \b1
        #CBM_ROW \b2
        #CBM_ROW \b3
        #CBM_ROW \b4
        #CBM_ROW \b5
        #CBM_ROW \b6
        #CBM_ROW \b7
.endmacro

UI_TILE_RECORD .macro index
.endmacro

#UI_TILE_RECORD UI_TILE_PANEL
ui_data_panel:
        .fill 64, $0C

#UI_TILE_RECORD UI_TILE_MENU
ui_data_menu:
        .fill 64, $0C       ; light grey -- matches UI_TILE_PANEL and UI_TEXT_BG

#UI_TILE_RECORD UI_TILE_STATUS_LIGHT
