        .byte $0B,$05,$05,$05,$05,$05,$05,$05
        .byte $0B,$05,$05,$05,$05,$05,$05,$05
        .byte $0B,$05,$05,$05,$05,$05,$05,$05
        .byte $0B,$05,$05,$05,$05,$05,$05,$05
        .byte $0B,$0B,$0B,$0B,$0B,$0B,$0B,$0B   ; tr
        .byte $05,$05,$05,$05,$05,$05,$05,$0B
        .byte $05,$05,$05,$05,$05,$05,$05,$0B
        .byte $05,$05,$05,$05,$05,$05,$05,$0B
        .byte $05,$05,$05,$05,$05,$05,$05,$0B
        .byte $05,$05,$05,$05,$05,$05,$05,$0B
        .byte $05,$05,$05,$05,$05,$05,$05,$0B
        .byte $05,$05,$05,$05,$05,$05,$05,$0B
        .byte $0B,$05,$05,$05,$05,$05,$05,$05   ; bl
        .byte $0B,$05,$05,$05,$05,$05,$05,$05
        .byte $0B,$05,$05,$05,$05,$05,$05,$05
        .byte $0B,$05,$05,$05,$05,$05,$05,$05
        .byte $0B,$05,$05,$05,$05,$05,$05,$05
        .byte $0B,$05,$05,$05,$05,$05,$05,$05
        .byte $0B,$05,$05,$05,$05,$05,$05,$05
